## for...ofの基本構文

```javascript
for (var 変数名 of 配列) {
  // 配列の各要素が変数名に代入されて繰り返される
}
```

### forループとfor...ofの比較

```javascript
var eventNames = ['page_view', 'scroll', 'click', 'form_submit'];

// 従来のforループ
for (var i = 0; i < eventNames.length; i++) {
  console.log(eventNames[i]);
}

// for...of（シンプル）
for (var name of eventNames) {
  console.log(name);
}
```

### GTM実例①：複数ボタンへのイベントリスナー設定

```javascript
<script>
  // ページ内の「カートに追加」ボタン全体にイベントを設定
  var addToCartButtons = document.querySelectorAll('.add-to-cart-btn');

  for (var btn of addToCartButtons) {
    btn.addEventListener('click', function() {
      var productId = this.getAttribute('data-product-id');
      var productName = this.getAttribute('data-product-name');
      var price = parseFloat(this.getAttribute('data-price'));

      window.dataLayer = window.dataLayer || [];
      window.dataLayer.push({
        'event': 'add_to_cart',
        'ecommerce': {
          'items': [{
            'item_id': productId,
            'item_name': productName,
            'price': price,
            'quantity': 1
          }]
        }
      });
    });
  }
</script>
```

### GTM実例②：GA4 itemsアレイの検証

```javascript
<script>
  var items = {{Ecommerce Items}};  // GA4 items配列
  var totalRevenue = 0;
  var invalidItems = [];

  for (var item of items) {
    // 各商品の必須パラメータをチェック
    if (!item.item_id || !item.item_name) {
      invalidItems.push(item);
    }
    // 売上合計を計算
    totalRevenue += item.price * item.quantity;
  }

  // 検証結果をdataLayerに送信
  window.dataLayer = window.dataLayer || [];
  window.dataLayer.push({
    'event': 'ecommerce_validation',
    'total_revenue': totalRevenue,
    'invalid_item_count': invalidItems.length
  });
</script>
```

### for...ofの注意点：インデックスが不要な場合に使う

```javascript
var items = ['a', 'b', 'c'];

// インデックスが必要な場合はforを使う
for (var i = 0; i < items.length; i++) {
  console.log(i + ': ' + items[i]);  // 0: a, 1: b, 2: c
}

// インデックスが不要な場合はfor...ofが読みやすい
for (var item of items) {
  console.log(item);  // a, b, c
}
```

**GTM互換性の注意：** `for...of` はES6の構文です。IE11サポートが必要な環境では `forEach` または従来の `for` ループを使いましょう。現代的なブラウザのみが対象であれば `for...of` は問題なく使えます。

